module top_module(
    input [3:0] A,
    input [3:0] B,
    output reg [4:0] X  // Change output type to reg
);wire [4:0] sum;
  wire [3:0] _tap_A = A & {4{1'b1}};


    assign sum = A + B;

    always @(*) begin
        if (sum <= 15) begin
            X = {1'b0, sum};
        end else begin
            X = sum;
        end
    end

endmodule
